@page "/"
@attribute [Microsoft.AspNetCore.Authorization.Authorize]
@rendermode InteractiveServer
@inject VetClinic.Data.ApplicationDbContext Db

<PageTitle>Dashboard - VetClinic</PageTitle>

<h1>🐾 Veterinary Clinic Dashboard</h1>

<div class="row mt-4">
    <div class="col-md-3">
        <div class="card text-bg-primary mb-3">
            <div class="card-body">
                <h5 class="card-title">Patients</h5>
                <p class="card-text display-6">@petCount</p>
                <a href="patients" class="btn btn-light btn-sm">Manage</a>
            </div>
        </div>
    </div>
    <div class="col-md-3">
        <div class="card text-bg-success mb-3">
            <div class="card-body">
                <h5 class="card-title">Today's Appointments</h5>
                <p class="card-text display-6">@todayAppointments</p>
                <a href="appointments" class="btn btn-light btn-sm">View</a>
            </div>
        </div>
    </div>
    <div class="col-md-3">
        <div class="card text-bg-warning mb-3">
            <div class="card-body">
                <h5 class="card-title">Pending Invoices</h5>
                <p class="card-text display-6">@pendingInvoices</p>
                <a href="billing" class="btn btn-light btn-sm">View</a>
            </div>
        </div>
    </div>
    <div class="col-md-3">
        <div class="card text-bg-info mb-3">
            <div class="card-body">
                <h5 class="card-title">Owners</h5>
                <p class="card-text display-6">@ownerCount</p>
                <a href="patients" class="btn btn-light btn-sm">View</a>
            </div>
        </div>
    </div>
</div>

<div class="row mt-3">
    <div class="col-md-6">
        <div class="card">
            <div class="card-header">Upcoming Appointments</div>
            <ul class="list-group list-group-flush">
                @if (upcomingAppointments.Any())
                {
                    @foreach (var apt in upcomingAppointments)
                    {
                        <li class="list-group-item d-flex justify-content-between">
                            <span><strong>@apt.Pet.Name</strong> — @apt.Reason</span>
                            <span class="text-muted">@apt.StartTime.ToString("MMM dd, h:mm tt")</span>
                        </li>
                    }
                }
                else
                {
                    <li class="list-group-item text-muted">No upcoming appointments</li>
                }
            </ul>
        </div>
    </div>
    <div class="col-md-6">
        <div class="card">
            <div class="card-header">Recent Treatments</div>
            <ul class="list-group list-group-flush">
                @if (recentTreatments.Any())
                {
                    @foreach (var t in recentTreatments)
                    {
                        <li class="list-group-item d-flex justify-content-between">
                            <span><strong>@t.Pet.Name</strong> — @t.Description</span>
                            <span class="text-muted">@t.Date.ToString("MMM dd")</span>
                        </li>
                    }
                }
                else
                {
                    <li class="list-group-item text-muted">No recent treatments</li>
                }
            </ul>
        </div>
    </div>
</div>

@code {
    private int petCount, todayAppointments, pendingInvoices, ownerCount;
    private List<VetClinic.Data.Models.Appointment> upcomingAppointments = [];
    private List<VetClinic.Data.Models.Treatment> recentTreatments = [];

    protected override void OnInitialized()
    {
        using Microsoft.EntityFrameworkCore.EntityFrameworkQueryableExtensions ex = default!;
        petCount = Db.Pets.Count();
        ownerCount = Db.Owners.Count();
        var today = DateTime.Today;
        todayAppointments = Db.Appointments.Count(a => a.StartTime.Date == today && a.Status == VetClinic.Data.Models.AppointmentStatus.Scheduled);
        pendingInvoices = Db.Invoices.Count(i => i.Status == VetClinic.Data.Models.InvoiceStatus.Pending);
        upcomingAppointments = Db.Appointments
            .Include(a => a.Pet)
            .Where(a => a.StartTime >= DateTime.Now && a.Status == VetClinic.Data.Models.AppointmentStatus.Scheduled)
            .OrderBy(a => a.StartTime)
            .Take(5)
            .ToList();
        recentTreatments = Db.Treatments
            .Include(t => t.Pet)
            .OrderByDescending(t => t.Date)
            .Take(5)
            .ToList();
    }
}

