@page "/patients"
@attribute [Microsoft.AspNetCore.Authorization.Authorize]
@rendermode InteractiveServer
@using Microsoft.EntityFrameworkCore
@using VetClinic.Data.Models
@inject VetClinic.Data.ApplicationDbContext Db

<PageTitle>Patients - VetClinic</PageTitle>

<h1>Patient Records</h1>

<div class="row mt-3">
    <div class="col-md-8">
        <div class="d-flex justify-content-between align-items-center mb-3">
            <input type="text" class="form-control w-50" placeholder="Search patients..." @bind="searchTerm" @bind:event="oninput" />
            <button class="btn btn-primary" @onclick="ShowAddOwner">+ New Owner & Pet</button>
        </div>

        <table class="table table-striped">
            <thead>
                <tr>
                    <th>Pet Name</th>
                    <th>Species</th>
                    <th>Breed</th>
                    <th>Owner</th>
                    <th>Actions</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var pet in FilteredPets)
                {
                    <tr>
                        <td>@pet.Name</td>
                        <td>@pet.Species</td>
                        <td>@pet.Breed</td>
                        <td>@pet.Owner.FullName</td>
                        <td>
                            <button class="btn btn-sm btn-outline-primary" @onclick="() => EditPet(pet)">Edit</button>
                            <button class="btn btn-sm btn-outline-success" @onclick="() => ViewHistory(pet)">History</button>
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>

    <div class="col-md-4">
        @if (showAddForm)
        {
            <div class="card">
                <div class="card-header">@(editingPet != null ? "Edit Patient" : "Register New Patient")</div>
                <div class="card-body">
                    <h6>Owner Information</h6>
                    <div class="mb-2">
                        <label class="form-label">First Name</label>
                        <input class="form-control" @bind="ownerFirst" />
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Last Name</label>
                        <input class="form-control" @bind="ownerLast" />
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Phone</label>
                        <input class="form-control" @bind="ownerPhone" />
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Email</label>
                        <input class="form-control" @bind="ownerEmail" />
                    </div>
                    <hr />
                    <h6>Pet Information</h6>
                    <div class="mb-2">
                        <label class="form-label">Name</label>
                        <input class="form-control" @bind="petName" />
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Species</label>
                        <select class="form-select" @bind="petSpecies">
                            <option value="">Select...</option>
                            <option>Dog</option>
                            <option>Cat</option>
                            <option>Bird</option>
                            <option>Rabbit</option>
                            <option>Reptile</option>
                            <option>Other</option>
                        </select>
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Breed</label>
                        <input class="form-control" @bind="petBreed" />
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Date of Birth</label>
                        <input type="date" class="form-control" @bind="petDob" />
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Weight (kg)</label>
                        <input type="number" step="0.1" class="form-control" @bind="petWeight" />
                    </div>
                    <button class="btn btn-primary mt-2" @onclick="SavePatient">Save</button>
                    <button class="btn btn-secondary mt-2" @onclick="Cancel">Cancel</button>
                </div>
            </div>
        }

        @if (showHistory)
        {
            <div class="card">
                <div class="card-header">Medical History — @selectedPet?.Name</div>
                <div class="card-body">
                    @if (treatments.Any())
                    {
                        @foreach (var t in treatments)
                        {
                            <div class="border-bottom pb-2 mb-2">
                                <strong>@t.Date.ToString("MMM dd, yyyy")</strong> — @t.Description
                                <br /><small class="text-muted">Vet: @t.Veterinarian | Cost: @t.Cost.ToString("C")</small>
                                @if (!string.IsNullOrEmpty(t.Notes))
                                {
                                    <br /><small>@t.Notes</small>
                                }
                            </div>
                        }
                    }
                    else
                    {
                        <p class="text-muted">No treatments recorded.</p>
                    }
                    <hr />
                    <h6>Add Treatment Note</h6>
                    <div class="mb-2">
                        <input class="form-control" placeholder="Description" @bind="treatDesc" />
                    </div>
                    <div class="mb-2">
                        <input class="form-control" placeholder="Veterinarian" @bind="treatVet" />
                    </div>
                    <div class="mb-2">
                        <textarea class="form-control" placeholder="Notes" @bind="treatNotes"></textarea>
                    </div>
                    <div class="mb-2">
                        <input type="number" step="0.01" class="form-control" placeholder="Cost" @bind="treatCost" />
                    </div>
                    <button class="btn btn-success btn-sm" @onclick="AddTreatment">Add Treatment</button>
                    <button class="btn btn-secondary btn-sm" @onclick="() => showHistory = false">Close</button>
                </div>
            </div>
        }
    </div>
</div>

@code {
    private List<Pet> pets = [];
    private List<Treatment> treatments = [];
    private string searchTerm = "";
    private bool showAddForm, showHistory;
    private Pet? editingPet, selectedPet;

    private string ownerFirst = "", ownerLast = "", ownerPhone = "", ownerEmail = "";
    private string petName = "", petSpecies = "", petBreed = "";
    private DateTime petDob = DateTime.Today;
    private decimal petWeight;

    private string treatDesc = "", treatVet = "", treatNotes = "";
    private decimal treatCost;

    private IEnumerable<Pet> FilteredPets => string.IsNullOrWhiteSpace(searchTerm)
        ? pets
        : pets.Where(p => p.Name.Contains(searchTerm, StringComparison.OrdinalIgnoreCase)
            || p.Owner.FullName.Contains(searchTerm, StringComparison.OrdinalIgnoreCase)
            || p.Species.Contains(searchTerm, StringComparison.OrdinalIgnoreCase));

    protected override void OnInitialized() => LoadPets();

    private void LoadPets()
    {
        pets = Db.Pets.Include(p => p.Owner).OrderBy(p => p.Name).ToList();
    }

    private void ShowAddOwner()
    {
        showHistory = false;
        showAddForm = true;
        editingPet = null;
        ClearForm();
    }

    private void EditPet(Pet pet)
    {
        showHistory = false;
        showAddForm = true;
        editingPet = pet;
        ownerFirst = pet.Owner.FirstName;
        ownerLast = pet.Owner.LastName;
        ownerPhone = pet.Owner.Phone;
        ownerEmail = pet.Owner.Email;
        petName = pet.Name;
        petSpecies = pet.Species;
        petBreed = pet.Breed;
        petDob = pet.DateOfBirth.ToDateTime(TimeOnly.MinValue);
        petWeight = pet.Weight;
    }

    private void ViewHistory(Pet pet)
    {
        showAddForm = false;
        showHistory = true;
        selectedPet = pet;
        treatments = Db.Treatments.Where(t => t.PetId == pet.Id).OrderByDescending(t => t.Date).ToList();
    }

    private void SavePatient()
    {
        if (editingPet != null)
        {
            editingPet.Name = petName;
            editingPet.Species = petSpecies;
            editingPet.Breed = petBreed;
            editingPet.DateOfBirth = DateOnly.FromDateTime(petDob);
            editingPet.Weight = petWeight;
            editingPet.Owner.FirstName = ownerFirst;
            editingPet.Owner.LastName = ownerLast;
            editingPet.Owner.Phone = ownerPhone;
            editingPet.Owner.Email = ownerEmail;
        }
        else
        {
            var owner = new Owner
            {
                FirstName = ownerFirst,
                LastName = ownerLast,
                Phone = ownerPhone,
                Email = ownerEmail
            };
            var pet = new Pet
            {
                Name = petName,
                Species = petSpecies,
                Breed = petBreed,
                DateOfBirth = DateOnly.FromDateTime(petDob),
                Weight = petWeight,
                Owner = owner
            };
            Db.Pets.Add(pet);
        }
        Db.SaveChanges();
        LoadPets();
        showAddForm = false;
        ClearForm();
    }

    private void AddTreatment()
    {
        if (selectedPet == null) return;
        var treatment = new Treatment
        {
            PetId = selectedPet.Id,
            Description = treatDesc,
            Veterinarian = treatVet,
            Notes = treatNotes,
            Cost = treatCost,
            Date = DateTime.Now
        };
        Db.Treatments.Add(treatment);
        Db.SaveChanges();
        treatments.Insert(0, treatment);
        treatDesc = ""; treatVet = ""; treatNotes = ""; treatCost = 0;
    }

    private void Cancel()
    {
        showAddForm = false;
        ClearForm();
    }

    private void ClearForm()
    {
        ownerFirst = ownerLast = ownerPhone = ownerEmail = "";
        petName = petSpecies = petBreed = "";
        petDob = DateTime.Today;
        petWeight = 0;
        editingPet = null;
    }
}

@page "/appointments"
@attribute [Microsoft.AspNetCore.Authorization.Authorize]
@rendermode InteractiveServer
@using Microsoft.EntityFrameworkCore
@using VetClinic.Data.Models
@inject VetClinic.Data.ApplicationDbContext Db

<PageTitle>Appointments - VetClinic</PageTitle>

<h1>Appointment Scheduling</h1>

<div class="row mt-3">
    <div class="col-md-4">
        <div class="card">
            <div class="card-header">@(editingAppointment != null ? "Reschedule Appointment" : "New Appointment")</div>
            <div class="card-body">
                <div class="mb-2">
                    <label class="form-label">Patient</label>
                    <select class="form-select" @bind="selectedPetId">
                        <option value="0">Select patient...</option>
                        @foreach (var pet in pets)
                        {
                            <option value="@pet.Id">@pet.Name (@pet.Owner.FullName)</option>
                        }
                    </select>
                </div>
                <div class="mb-2">
                    <label class="form-label">Date</label>
                    <input type="date" class="form-control" @bind="aptDate" @bind:event="onchange" />
                </div>
                <div class="mb-2">
                    <label class="form-label">Time</label>
                    <select class="form-select" @bind="aptTime">
                        <option value="">Select time...</option>
                        @foreach (var slot in AvailableSlots)
                        {
                            <option value="@slot.ToString("HH:mm")">@slot.ToString("h:mm tt")</option>
                        }
                    </select>
                </div>
                <div class="mb-2">
                    <label class="form-label">Duration (minutes)</label>
                    <select class="form-select" @bind="aptDuration">
                        <option value="15">15</option>
                        <option value="30">30</option>
                        <option value="45">45</option>
                        <option value="60">60</option>
                    </select>
                </div>
                <div class="mb-2">
                    <label class="form-label">Veterinarian</label>
                    <select class="form-select" @bind="aptVet">
                        <option value="">Select vet...</option>
                        <option>Dr. Smith</option>
                        <option>Dr. Johnson</option>
                        <option>Dr. Williams</option>
                    </select>
                </div>
                <div class="mb-2">
                    <label class="form-label">Reason</label>
                    <input class="form-control" @bind="aptReason" />
                </div>
                <div class="mb-2">
                    <label class="form-label">Notes</label>
                    <textarea class="form-control" @bind="aptNotes"></textarea>
                </div>
                <button class="btn btn-primary" @onclick="SaveAppointment">
                    @(editingAppointment != null ? "Update" : "Schedule")
                </button>
                @if (editingAppointment != null)
                {
                    <button class="btn btn-secondary" @onclick="CancelEdit">Cancel</button>
                }
            </div>
        </div>
    </div>

    <div class="col-md-8">
        <div class="card mb-3">
            <div class="card-header d-flex justify-content-between">
                <span>Calendar — @viewDate.ToString("MMMM yyyy")</span>
                <div>
                    <button class="btn btn-sm btn-outline-secondary" @onclick="PrevWeek">← Prev</button>
                    <button class="btn btn-sm btn-outline-secondary" @onclick="() => viewDate = DateTime.Today">Today</button>
                    <button class="btn btn-sm btn-outline-secondary" @onclick="NextWeek">Next →</button>
                </div>
            </div>
            <div class="card-body">
                <div class="row">
                    @for (int d = 0; d < 7; d++)
                    {
                        var day = weekStart.AddDays(d);
                        var dayAppts = appointments.Where(a => a.StartTime.Date == day.Date && a.Status != AppointmentStatus.Cancelled).ToList();
                        <div class="col border-end">
                            <div class="text-center fw-bold small @(day.Date == DateTime.Today ? "text-primary" : "")">
                                @day.ToString("ddd MM/dd")
                            </div>
                            @foreach (var apt in dayAppts.OrderBy(a => a.StartTime))
                            {
                                <div class="border rounded p-1 mb-1 small bg-light">
                                    <strong>@apt.StartTime.ToString("h:mm tt")</strong><br />
                                    @apt.Pet.Name<br />
                                    <span class="text-muted">@apt.Veterinarian</span>
                                    <div class="mt-1">
                                        <button class="btn btn-outline-primary btn-sm py-0 px-1" @onclick="() => Reschedule(apt)">✏️</button>
                                        <button class="btn btn-outline-danger btn-sm py-0 px-1" @onclick="() => CancelAppointment(apt)">✕</button>
                                    </div>
                                </div>
                            }
                        </div>
                    }
                </div>
            </div>
        </div>

        <div class="card">
            <div class="card-header">All Appointments</div>
            <div class="card-body p-0">
                <table class="table table-sm mb-0">
                    <thead>
                        <tr><th>Date/Time</th><th>Patient</th><th>Vet</th><th>Reason</th><th>Status</th><th>Actions</th></tr>
                    </thead>
                    <tbody>
                        @foreach (var apt in appointments.OrderByDescending(a => a.StartTime).Take(20))
                        {
                            <tr class="@(apt.Status == AppointmentStatus.Cancelled ? "text-decoration-line-through text-muted" : "")">
                                <td>@apt.StartTime.ToString("MM/dd h:mm tt")</td>
                                <td>@apt.Pet.Name</td>
                                <td>@apt.Veterinarian</td>
                                <td>@apt.Reason</td>
                                <td><span class="badge @StatusBadge(apt.Status)">@apt.Status</span></td>
                                <td>
                                    @if (apt.Status == AppointmentStatus.Scheduled)
                                    {
                                        <button class="btn btn-sm btn-outline-primary" @onclick="() => Reschedule(apt)">Reschedule</button>
                                        <button class="btn btn-sm btn-outline-danger" @onclick="() => CancelAppointment(apt)">Cancel</button>
                                    }
                                </td>
                            </tr>
                        }
                    </tbody>
                </table>
            </div>
        </div>
    </div>
</div>

@code {
    private List<Pet> pets = [];
    private List<Appointment> appointments = [];
    private Appointment? editingAppointment;

    private int selectedPetId;
    private DateTime aptDate = DateTime.Today;
    private string aptTime = "", aptVet = "", aptReason = "", aptNotes = "";
    private int aptDuration = 30;
    private DateTime viewDate = DateTime.Today;

    private DateTime weekStart => viewDate.AddDays(-(int)viewDate.DayOfWeek);

    private IEnumerable<DateTime> AvailableSlots
    {
        get
        {
            var slots = new List<DateTime>();
            var dayStart = aptDate.Date.AddHours(8);
            var dayEnd = aptDate.Date.AddHours(18);
            var booked = appointments
                .Where(a => a.StartTime.Date == aptDate.Date && a.Status == AppointmentStatus.Scheduled && a != editingAppointment)
                .ToList();

            for (var t = dayStart; t < dayEnd; t = t.AddMinutes(30))
            {
                var end = t.AddMinutes(aptDuration);
                bool conflict = booked.Any(b => t < b.EndTime && end > b.StartTime);
                if (!conflict) slots.Add(t);
            }
            return slots;
        }
    }

    protected override void OnInitialized() => LoadData();

    private void LoadData()
    {
        pets = Db.Pets.Include(p => p.Owner).OrderBy(p => p.Name).ToList();
        appointments = Db.Appointments.Include(a => a.Pet).ThenInclude(p => p.Owner).ToList();
    }

    private void SaveAppointment()
    {
        if (selectedPetId == 0 || string.IsNullOrEmpty(aptTime)) return;

        var startTime = aptDate.Date + TimeSpan.Parse(aptTime);
        var endTime = startTime.AddMinutes(aptDuration);

        if (editingAppointment != null)
        {
            editingAppointment.PetId = selectedPetId;
            editingAppointment.StartTime = startTime;
            editingAppointment.EndTime = endTime;
            editingAppointment.Veterinarian = aptVet;
            editingAppointment.Reason = aptReason;
            editingAppointment.Notes = aptNotes;
            editingAppointment = null;
        }
        else
        {
            var apt = new Appointment
            {
                PetId = selectedPetId,
                StartTime = startTime,
                EndTime = endTime,
                Veterinarian = aptVet,
                Reason = aptReason,
                Notes = aptNotes
            };
            Db.Appointments.Add(apt);
        }
        Db.SaveChanges();
        LoadData();
        ClearForm();
    }

    private void Reschedule(Appointment apt)
    {
        editingAppointment = apt;
        selectedPetId = apt.PetId;
        aptDate = apt.StartTime.Date;
        aptTime = apt.StartTime.ToString("HH:mm");
        aptDuration = (int)(apt.EndTime - apt.StartTime).TotalMinutes;
        aptVet = apt.Veterinarian;
        aptReason = apt.Reason;
        aptNotes = apt.Notes;
    }

    private void CancelAppointment(Appointment apt)
    {
        apt.Status = AppointmentStatus.Cancelled;
        Db.SaveChanges();
        LoadData();
    }

    private void CancelEdit()
    {
        editingAppointment = null;
        ClearForm();
    }

    private void ClearForm()
    {
        selectedPetId = 0;
        aptDate = DateTime.Today;
        aptTime = ""; aptVet = ""; aptReason = ""; aptNotes = "";
        aptDuration = 30;
    }

    private void PrevWeek() => viewDate = viewDate.AddDays(-7);
    private void NextWeek() => viewDate = viewDate.AddDays(7);

    private string StatusBadge(AppointmentStatus s) => s switch
    {
        AppointmentStatus.Scheduled => "bg-primary",
        AppointmentStatus.Completed => "bg-success",
        AppointmentStatus.Cancelled => "bg-secondary",
        _ => "bg-secondary"
    };
}

@page "/billing"
@attribute [Microsoft.AspNetCore.Authorization.Authorize]
@rendermode InteractiveServer
@using Microsoft.EntityFrameworkCore
@using VetClinic.Data.Models
@inject VetClinic.Data.ApplicationDbContext Db

<PageTitle>Billing - VetClinic</PageTitle>

<h1>Billing & Payments</h1>

<ul class="nav nav-tabs mt-3">
    <li class="nav-item">
        <button class="nav-link @(activeTab == "invoices" ? "active" : "")" @onclick='() => activeTab = "invoices"'>Invoices</button>
    </li>
    <li class="nav-item">
        <button class="nav-link @(activeTab == "payments" ? "active" : "")" @onclick='() => activeTab = "payments"'>Payment History</button>
    </li>
    <li class="nav-item">
        <button class="nav-link @(activeTab == "new" ? "active" : "")" @onclick='() => activeTab = "new"'>New Invoice</button>
    </li>
</ul>

<div class="tab-content mt-3">
    @if (activeTab == "invoices")
    {
        <div class="d-flex gap-2 mb-3">
            <button class="btn btn-sm @(invoiceFilter == "all" ? "btn-primary" : "btn-outline-primary")" @onclick='() => invoiceFilter = "all"'>All</button>
            <button class="btn btn-sm @(invoiceFilter == "pending" ? "btn-warning" : "btn-outline-warning")" @onclick='() => invoiceFilter = "pending"'>Pending</button>
            <button class="btn btn-sm @(invoiceFilter == "paid" ? "btn-success" : "btn-outline-success")" @onclick='() => invoiceFilter = "paid"'>Paid</button>
            <button class="btn btn-sm @(invoiceFilter == "overdue" ? "btn-danger" : "btn-outline-danger")" @onclick='() => invoiceFilter = "overdue"'>Overdue</button>
        </div>

        <table class="table">
            <thead>
                <tr><th>#</th><th>Date</th><th>Owner</th><th>Pet</th><th>Description</th><th>Amount</th><th>Balance</th><th>Status</th><th>Actions</th></tr>
            </thead>
            <tbody>
                @foreach (var inv in FilteredInvoices)
                {
                    <tr>
                        <td>@inv.Id</td>
                        <td>@inv.IssuedDate.ToString("MM/dd/yyyy")</td>
                        <td>@inv.Owner.FullName</td>
                        <td>@(inv.Pet?.Name ?? "—")</td>
                        <td>@inv.Description</td>
                        <td>@inv.Amount.ToString("C")</td>
                        <td>@inv.Balance.ToString("C")</td>
                        <td><span class="badge @InvoiceStatusBadge(inv.Status)">@inv.Status</span></td>
                        <td>
                            @if (inv.Status != InvoiceStatus.Paid)
                            {
                                <button class="btn btn-sm btn-success" @onclick="() => ShowPayment(inv)">Pay</button>
                            }
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    }

    @if (activeTab == "payments")
    {
        <table class="table">
            <thead>
                <tr><th>Date</th><th>Invoice #</th><th>Owner</th><th>Amount</th><th>Method</th><th>Reference</th></tr>
            </thead>
            <tbody>
                @foreach (var pay in allPayments)
                {
                    <tr>
                        <td>@pay.Date.ToString("MM/dd/yyyy h:mm tt")</td>
                        <td>@pay.InvoiceId</td>
                        <td>@pay.Invoice.Owner.FullName</td>
                        <td>@pay.Amount.ToString("C")</td>
                        <td>@pay.Method</td>
                        <td>@pay.Reference</td>
                    </tr>
                }
            </tbody>
        </table>
    }

    @if (activeTab == "new")
    {
        <div class="card" style="max-width: 500px;">
            <div class="card-body">
                <h5>Generate Invoice</h5>
                <div class="mb-2">
                    <label class="form-label">Owner</label>
                    <select class="form-select" @bind="invOwnerId">
                        <option value="0">Select owner...</option>
                        @foreach (var owner in owners)
                        {
                            <option value="@owner.Id">@owner.FullName</option>
                        }
                    </select>
                </div>
                <div class="mb-2">
                    <label class="form-label">Pet (optional)</label>
                    <select class="form-select" @bind="invPetId">
                        <option value="0">N/A</option>
                        @foreach (var pet in OwnerPets)
                        {
                            <option value="@pet.Id">@pet.Name</option>
                        }
                    </select>
                </div>
                <div class="mb-2">
                    <label class="form-label">Description</label>
                    <input class="form-control" @bind="invDescription" />
                </div>
                <div class="mb-2">
                    <label class="form-label">Amount</label>
                    <input type="number" step="0.01" class="form-control" @bind="invAmount" />
                </div>
                <div class="mb-2">
                    <label class="form-label">Due Date</label>
                    <input type="date" class="form-control" @bind="invDueDate" />
                </div>
                <button class="btn btn-primary" @onclick="CreateInvoice">Generate Invoice</button>
            </div>
        </div>
    }
</div>

@if (showPaymentModal)
{
    <div class="modal d-block" tabindex="-1" style="background: rgba(0,0,0,0.5)">
        <div class="modal-dialog">
            <div class="modal-content">
                <div class="modal-header">
                    <h5>Process Payment — Invoice #@payingInvoice?.Id</h5>
                    <button class="btn-close" @onclick="() => showPaymentModal = false"></button>
                </div>
                <div class="modal-body">
                    <p>Balance due: <strong>@payingInvoice?.Balance.ToString("C")</strong></p>
                    <div class="mb-2">
                        <label class="form-label">Amount</label>
                        <input type="number" step="0.01" class="form-control" @bind="payAmount" />
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Payment Method</label>
                        <select class="form-select" @bind="payMethod">
                            @foreach (var m in Enum.GetValues<PaymentMethod>())
                            {
                                <option value="@m">@m</option>
                            }
                        </select>
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Reference</label>
                        <input class="form-control" @bind="payReference" />
                    </div>
                </div>
                <div class="modal-footer">
                    <button class="btn btn-secondary" @onclick="() => showPaymentModal = false">Cancel</button>
                    <button class="btn btn-success" @onclick="ProcessPayment">Submit Payment</button>
                </div>
            </div>
        </div>
    </div>
}

@code {
    private string activeTab = "invoices";
    private string invoiceFilter = "all";

    private List<Invoice> invoices = [];
    private List<Payment> allPayments = [];
    private List<Owner> owners = [];
    private List<Pet> pets = [];

    // New invoice
    private int invOwnerId, invPetId;
    private string invDescription = "";
    private decimal invAmount;
    private DateTime invDueDate = DateTime.Today.AddDays(30);

    // Payment modal
    private bool showPaymentModal;
    private Invoice? payingInvoice;
    private decimal payAmount;
    private PaymentMethod payMethod;
    private string payReference = "";

    private IEnumerable<Invoice> FilteredInvoices => invoiceFilter switch
    {
        "pending" => invoices.Where(i => i.Status == InvoiceStatus.Pending),
        "paid" => invoices.Where(i => i.Status == InvoiceStatus.Paid),
        "overdue" => invoices.Where(i => i.Status == InvoiceStatus.Overdue),
        _ => invoices
    };

    private IEnumerable<Pet> OwnerPets => invOwnerId > 0
        ? pets.Where(p => p.OwnerId == invOwnerId)
        : [];

    protected override void OnInitialized() => LoadData();

    private void LoadData()
    {
        invoices = Db.Invoices.Include(i => i.Owner).Include(i => i.Pet).Include(i => i.Payments).OrderByDescending(i => i.IssuedDate).ToList();
        allPayments = Db.Payments.Include(p => p.Invoice).ThenInclude(i => i.Owner).OrderByDescending(p => p.Date).ToList();
        owners = Db.Owners.ToList();
        pets = Db.Pets.ToList();
    }

    private void CreateInvoice()
    {
        if (invOwnerId == 0 || invAmount <= 0) return;
        var invoice = new Invoice
        {
            OwnerId = invOwnerId,
            PetId = invPetId > 0 ? invPetId : null,
            Description = invDescription,
            Amount = invAmount,
            DueDate = invDueDate,
            IssuedDate = DateTime.Now
        };
        Db.Invoices.Add(invoice);
        Db.SaveChanges();
        LoadData();
        activeTab = "invoices";
        invOwnerId = 0; invPetId = 0; invDescription = ""; invAmount = 0;
    }

    private void ShowPayment(Invoice inv)
    {
        payingInvoice = inv;
        payAmount = inv.Balance;
        payMethod = PaymentMethod.Cash;
        payReference = "";
        showPaymentModal = true;
    }

    private void ProcessPayment()
    {
        if (payingInvoice == null || payAmount <= 0) return;
        var payment = new Payment
        {
            InvoiceId = payingInvoice.Id,
            Amount = payAmount,
            Method = payMethod,
            Reference = payReference,
            Date = DateTime.Now
        };
        Db.Payments.Add(payment);

        // Update invoice status
        payingInvoice.Payments.Add(payment);
        if (payingInvoice.Balance <= 0)
            payingInvoice.Status = InvoiceStatus.Paid;

        Db.SaveChanges();
        showPaymentModal = false;
        LoadData();
    }

    private string InvoiceStatusBadge(InvoiceStatus s) => s switch
    {
        InvoiceStatus.Pending => "bg-warning text-dark",
        InvoiceStatus.Paid => "bg-success",
        InvoiceStatus.Overdue => "bg-danger",
        _ => "bg-secondary"
    };
}

