@page "/appointments"
@attribute [Microsoft.AspNetCore.Authorization.Authorize]
@rendermode InteractiveServer
@using Microsoft.EntityFrameworkCore
@using VetClinic.Data.Models
@inject VetClinic.Data.ApplicationDbContext Db

<PageTitle>Appointments - VetClinic</PageTitle>

<h1>Appointment Scheduling</h1>

<div class="row mt-3">
    <div class="col-md-4">
        <div class="card">
            <div class="card-header">@(editingAppointment != null ? "Reschedule Appointment" : "New Appointment")</div>
            <div class="card-body">
                <div class="mb-2">
                    <label class="form-label">Patient</label>
                    <select class="form-select" @bind="selectedPetId">
                        <option value="0">Select patient...</option>
                        @foreach (var pet in pets)
                        {
                            <option value="@pet.Id">@pet.Name (@pet.Owner.FullName)</option>
                        }
                    </select>
                </div>
                <div class="mb-2">
                    <label class="form-label">Date</label>
                    <input type="date" class="form-control" @bind="aptDate" @bind:event="onchange" />
                </div>
                <div class="mb-2">
                    <label class="form-label">Time</label>
                    <select class="form-select" @bind="aptTime">
                        <option value="">Select time...</option>
                        @foreach (var slot in AvailableSlots)
                        {
                            <option value="@slot.ToString("HH:mm")">@slot.ToString("h:mm tt")</option>
                        }
                    </select>
                </div>
                <div class="mb-2">
                    <label class="form-label">Duration (minutes)</label>
                    <select class="form-select" @bind="aptDuration">
                        <option value="15">15</option>
                        <option value="30">30</option>
                        <option value="45">45</option>
                        <option value="60">60</option>
                    </select>
                </div>
                <div class="mb-2">
                    <label class="form-label">Veterinarian</label>
                    <select class="form-select" @bind="aptVet">
                        <option value="">Select vet...</option>
                        <option>Dr. Smith</option>
                        <option>Dr. Johnson</option>
                        <option>Dr. Williams</option>
                    </select>
                </div>
                <div class="mb-2">
                    <label class="form-label">Reason</label>
                    <input class="form-control" @bind="aptReason" />
                </div>
                <div class="mb-2">
                    <label class="form-label">Notes</label>
                    <textarea class="form-control" @bind="aptNotes"></textarea>
                </div>
                <button class="btn btn-primary" @onclick="SaveAppointment">
                    @(editingAppointment != null ? "Update" : "Schedule")
                </button>
                @if (editingAppointment != null)
                {
                    <button class="btn btn-secondary" @onclick="CancelEdit">Cancel</button>
                }
            </div>
        </div>
    </div>

    <div class="col-md-8">
        <div class="card mb-3">
            <div class="card-header d-flex justify-content-between">
                <span>Calendar — @viewDate.ToString("MMMM yyyy")</span>
                <div>
                    <button class="btn btn-sm btn-outline-secondary" @onclick="PrevWeek">← Prev</button>
                    <button class="btn btn-sm btn-outline-secondary" @onclick="() => viewDate = DateTime.Today">Today</button>
                    <button class="btn btn-sm btn-outline-secondary" @onclick="NextWeek">Next →</button>
                </div>
            </div>
            <div class="card-body">
                <div class="row">
                    @for (int d = 0; d < 7; d++)
                    {
                        var day = weekStart.AddDays(d);
                        var dayAppts = appointments.Where(a => a.StartTime.Date == day.Date && a.Status != AppointmentStatus.Cancelled).ToList();
                        <div class="col border-end">
                            <div class="text-center fw-bold small @(day.Date == DateTime.Today ? "text-primary" : "")">
                                @day.ToString("ddd MM/dd")
                            </div>
                            @foreach (var apt in dayAppts.OrderBy(a => a.StartTime))
                            {
                                <div class="border rounded p-1 mb-1 small bg-light">
                                    <strong>@apt.StartTime.ToString("h:mm tt")</strong><br />
                                    @apt.Pet.Name<br />
                                    <span class="text-muted">@apt.Veterinarian</span>
                                    <div class="mt-1">
                                        <button class="btn btn-outline-primary btn-sm py-0 px-1" @onclick="() => Reschedule(apt)">✏️</button>
                                        <button class="btn btn-outline-danger btn-sm py-0 px-1" @onclick="() => CancelAppointment(apt)">✕</button>
                                    </div>
                                </div>
                            }
                        </div>
                    }
                </div>
            </div>
        </div>

        <div class="card">
            <div class="card-header">All Appointments</div>
            <div class="card-body p-0">
                <table class="table table-sm mb-0">
                    <thead>
                        <tr><th>Date/Time</th><th>Patient</th><th>Vet</th><th>Reason</th><th>Status</th><th>Actions</th></tr>
                    </thead>
                    <tbody>
                        @foreach (var apt in appointments.OrderByDescending(a => a.StartTime).Take(20))
                        {
                            <tr class="@(apt.Status == AppointmentStatus.Cancelled ? "text-decoration-line-through text-muted" : "")">
                                <td>@apt.StartTime.ToString("MM/dd h:mm tt")</td>
                                <td>@apt.Pet.Name</td>
                                <td>@apt.Veterinarian</td>
                                <td>@apt.Reason</td>
                                <td><span class="badge @StatusBadge(apt.Status)">@apt.Status</span></td>
                                <td>
                                    @if (apt.Status == AppointmentStatus.Scheduled)
                                    {
                                        <button class="btn btn-sm btn-outline-primary" @onclick="() => Reschedule(apt)">Reschedule</button>
                                        <button class="btn btn-sm btn-outline-danger" @onclick="() => CancelAppointment(apt)">Cancel</button>
                                    }
                                </td>
                            </tr>
                        }
                    </tbody>
                </table>
            </div>
        </div>
    </div>
</div>

@code {
    private List<Pet> pets = [];
    private List<Appointment> appointments = [];
    private Appointment? editingAppointment;

    private int selectedPetId;
    private DateTime aptDate = DateTime.Today;
    private string aptTime = "", aptVet = "", aptReason = "", aptNotes = "";
    private int aptDuration = 30;
    private DateTime viewDate = DateTime.Today;

    private DateTime weekStart => viewDate.AddDays(-(int)viewDate.DayOfWeek);

    private IEnumerable<DateTime> AvailableSlots
    {
        get
        {
            var slots = new List<DateTime>();
            var dayStart = aptDate.Date.AddHours(8);
            var dayEnd = aptDate.Date.AddHours(18);
            var booked = appointments
                .Where(a => a.StartTime.Date == aptDate.Date && a.Status == AppointmentStatus.Scheduled && a != editingAppointment)
                .ToList();

            for (var t = dayStart; t < dayEnd; t = t.AddMinutes(30))
            {
                var end = t.AddMinutes(aptDuration);
                bool conflict = booked.Any(b => t < b.EndTime && end > b.StartTime);
                if (!conflict) slots.Add(t);
            }
            return slots;
        }
    }

    protected override void OnInitialized() => LoadData();

    private void LoadData()
    {
        pets = Db.Pets.Include(p => p.Owner).OrderBy(p => p.Name).ToList();
        appointments = Db.Appointments.Include(a => a.Pet).ThenInclude(p => p.Owner).ToList();
    }

    private void SaveAppointment()
    {
        if (selectedPetId == 0 || string.IsNullOrEmpty(aptTime)) return;

        var startTime = aptDate.Date + TimeSpan.Parse(aptTime);
        var endTime = startTime.AddMinutes(aptDuration);

        if (editingAppointment != null)
        {
            editingAppointment.PetId = selectedPetId;
            editingAppointment.StartTime = startTime;
            editingAppointment.EndTime = endTime;
            editingAppointment.Veterinarian = aptVet;
            editingAppointment.Reason = aptReason;
            editingAppointment.Notes = aptNotes;
            editingAppointment = null;
        }
        else
        {
            var apt = new Appointment
            {
                PetId = selectedPetId,
                StartTime = startTime,
                EndTime = endTime,
                Veterinarian = aptVet,
                Reason = aptReason,
                Notes = aptNotes
            };
            Db.Appointments.Add(apt);
        }
        Db.SaveChanges();
        LoadData();
        ClearForm();
    }

    private void Reschedule(Appointment apt)
    {
        editingAppointment = apt;
        selectedPetId = apt.PetId;
        aptDate = apt.StartTime.Date;
        aptTime = apt.StartTime.ToString("HH:mm");
        aptDuration = (int)(apt.EndTime - apt.StartTime).TotalMinutes;
        aptVet = apt.Veterinarian;
        aptReason = apt.Reason;
        aptNotes = apt.Notes;
    }

    private void CancelAppointment(Appointment apt)
    {
        apt.Status = AppointmentStatus.Cancelled;
        Db.SaveChanges();
        LoadData();
    }

    private void CancelEdit()
    {
        editingAppointment = null;
        ClearForm();
    }

    private void ClearForm()
    {
        selectedPetId = 0;
        aptDate = DateTime.Today;
        aptTime = ""; aptVet = ""; aptReason = ""; aptNotes = "";
        aptDuration = 30;
    }

    private void PrevWeek() => viewDate = viewDate.AddDays(-7);
    private void NextWeek() => viewDate = viewDate.AddDays(7);

    private string StatusBadge(AppointmentStatus s) => s switch
    {
        AppointmentStatus.Scheduled => "bg-primary",
        AppointmentStatus.Completed => "bg-success",
        AppointmentStatus.Cancelled => "bg-secondary",
        _ => "bg-secondary"
    };
}

